export const lpic2_quiz_pool = [
  // Topic 200: Capacity Planning
  { id: 'lpic2-200-1', topicId: 1, question: 'Welcher Befehl bietet eine dynamische Echtzeitansicht des Systems und der laufenden Prozesse und hebt die CPU- und Speicherauslastung hervor?', options: ['free', 'top', 'uptime', 'vmstat'], answer: 1, explanation: 'Der Befehl `top` bietet eine Echtzeit-Ansicht der Systemaktivität.' },
  { id: 'lpic2-200-2', topicId: 1, question: 'Welchen der folgenden Befehle würden Sie verwenden, um detaillierte E/A-Statistiken für Blockgeräte anzuzeigen?', options: ['vmstat', 'iostat', 'netstat', 'mpstat'], answer: 1, explanation: 'Der Befehl `iostat` wird verwendet, um die Auslastung von Eingabe-/Ausgabegeräten zu überwachen.' },
  { id: 'lpic2-200-3', topicId: 1, question: 'Sie möchten Systemleistungstrends über mehrere Monate sammeln und visualisieren. Welches Werkzeug ist dafür am besten geeignet?', options: ['top', 'ss', 'Collectd/MRTG/Cacti', 'tcpdump'], answer: 2, explanation: 'Collectd, MRTG und Cacti sind Standardwerkzeuge, um Daten über die Zeit zu sammeln und Diagramme für die Kapazitätsplanung zu erstellen.' },
  { id: 'lpic2-200-4', topicId: 1, question: 'Welches Tool können Sie verwenden, um zukünftig benötigte Kapazitäten basierend auf Traffic-Trends vorherzusagen?', options: ['mrtg', 'ping', 'fsck', 'ls'], answer: 0, explanation: 'MRTG (Multi Router Traffic Grapher) wird verwendet, um Traffic und Kapazität über einen Zeitraum zu überwachen.' },
  { id: 'lpic2-200-5', topicId: 1, question: 'Was ist der Zweck des Befehls `sar`?', options: ['Dateien auf dem Datenträger suchen', 'System Activity Reporter (Berichtet über die Systemaktivität)', 'Backup-Archive speichern', 'Alle Prozesse beenden'], answer: 1, explanation: '`sar` ist Teil von sysstat und wird zum Sammeln, Melden und Speichern von Systemaktivitäten verwendet.' },

  // Topic 201: Linux Kernel
  { id: 'lpic2-201-1', topicId: 2, question: 'Wo befinden sich kompilierte Kernel-Module standardmäßig im Dateisystem?', options: ['/boot/modules/', '/lib/modules/$(uname -r)/', '/etc/kernel/', '/var/lib/modules/'], answer: 1, explanation: 'Kernelmodule werden unter `/lib/modules/` in einem Ordner gespeichert, der der spezifischen Kernelversion entspricht.' },
  { id: 'lpic2-201-2', topicId: 2, question: 'Welches make-Ziel (Target) wird verwendet, um ein modernes, komprimiertes Kernel-Image zu erstellen?', options: ['make zImage', 'make bzImage', 'make vmlinux', 'make install'], answer: 1, explanation: '`make bzImage` erstellt ein komprimiertes Kernel-Image (big zImage), das architektonische Einschränkungen von zImage umgeht.' },
  { id: 'lpic2-201-3', topicId: 2, question: 'Welcher Befehl bietet bei der Kernelkompilierung aus dem Quellcode eine textbasierte, menügesteuerte Schnittstelle?', options: ['make config', 'make menuconfig', 'make xconfig', 'make defconfig'], answer: 1, explanation: '`make menuconfig` erfordert ncurses und bietet eine textbasierte Konsolenschnittstelle.' },
  { id: 'lpic2-201-4', topicId: 2, question: 'Welches Werkzeug wird verwendet, um ein Kernelmodul samt all seinen Abhängigkeiten intelligent zu laden?', options: ['insmod', 'modinfo', 'modprobe', 'rmmod'], answer: 2, explanation: '`modprobe` fügt Kernelmodule hinzu oder entfernt sie und löst deren Abhängigkeiten automatisch auf.' },
  { id: 'lpic2-201-5', topicId: 2, question: 'Welche Datei dient als Symboltabelle des Kernels und ordnet Speicheradressen für das Debugging zu?', options: ['vmlinux', 'System.map', 'bzImage', 'initrd'], answer: 1, explanation: 'Die Datei `System.map` enthält die Speicheradressen (Symbole) der Kernelfunktionen.' },

  // Topic 202: System Startup
  { id: 'lpic2-202-1', topicId: 3, question: 'In welchem System wird das Standard-Runlevel unter SysVinit für den Start festgelegt?', options: ['/etc/inittab', '/etc/runlevel', '/boot/grub/grub.cfg', '/etc/init.d/rcS'], answer: 0, explanation: 'Die Datei `/etc/inittab` definiert das initdefault Runlevel.' },
  { id: 'lpic2-202-2', topicId: 3, question: 'Mit welchem Befehl wird die Konfigurationsdatei für GRUB 2 auf Debian/Ubuntu-Systemen aktualisiert?', options: ['grub-install', 'grub2-mkconfig', 'update-grub', 'grub-setup'], answer: 2, explanation: '`update-grub` ist das Debian-Skript, das im Hintergrund `grub-mkconfig` ausführt.' },
  { id: 'lpic2-202-3', topicId: 3, question: 'Während einer Wiederherstellung müssen Sie unter systemd im Einzelbenutzermodus starten. Welches Target wird verwendet?', options: ['runlevel1.target', 'rescue.target', 'single.target', 'emergency.target'], answer: 1, explanation: 'Das Target `rescue.target` ist das systemd-Äquivalent zum SysVinit Single-User Mode.' },
  { id: 'lpic2-202-4', topicId: 3, question: 'Wo wird die endgültige generierte Konfigurationsdatei für GRUB 2 typischerweise gespeichert?', options: ['/boot/grub/grub.conf', '/boot/grub2/grub2.cfg', '/boot/grub/grub.cfg', '/etc/grub.cfg'], answer: 2, explanation: 'Die Hauptdatei von GRUB 2 wird in `/boot/grub/grub.cfg` (oder grub2/ je nach Distribution) generiert.' },
  { id: 'lpic2-202-5', topicId: 3, question: 'Welchen Parameter hängen Sie in GRUB an die Kernel-Befehlszeile an, um systemd/init zu umgehen und direkt eine Root-Shell zu erhalten?', options: ['init=/bin/sh', 'single', 'rescue', 'bash'], answer: 0, explanation: 'Durch Hinzufügen von `init=/bin/sh` wird der Kernel angewiesen, direkt die Shell zu starten.' },

  // Topic 203: Filesystem and Devices
  { id: 'lpic2-203-1', topicId: 4, question: 'Welches auf Extents basierende Dateisystem ist für die RHEL-Familie (Red Hat 7+) zum Standard geworden?', options: ['ext4', 'xfs', 'btrfs', 'zfs'], answer: 1, explanation: 'XFS ist extrem skalierbar im E/A-Bereich und wurde von Red Hat als Standard gewählt.' },
  { id: 'lpic2-203-2', topicId: 4, question: 'Mit welchem Befehl überprüfen Sie ein ext4-Dateisystem auf Fehler?', options: ['fsck.ext4', 'e2fsck', 'A und B', 'xfs_repair'], answer: 2, explanation: '`fsck.ext4` ist oft ein symbolischer Link oder Wrapper, der auf `e2fsck` zeigt.' },
  { id: 'lpic2-203-3', topicId: 4, question: 'Was ist der Zweck der Datei `/etc/fstab`?', options: ['Netzwerkschnittstellen konfigurieren', 'Statische Dateisysteme auflisten, die beim Booten gemountet werden', 'Passwörter speichern', 'Den Bootsektor verwalten'], answer: 1, explanation: 'Die fstab (File Systems Table) sagt dem System, wie Festplattenpartitionen eingebunden werden.' },
  { id: 'lpic2-203-4', topicId: 4, question: 'S.M.A.R.T. Kurztest - Welche Option in smartctl gibt eine schnelle (PASSED/FAILED) S.M.A.R.T.-Gesundheitsbewertung?', options: ['-a', '-H', '-i', '-t short'], answer: 1, explanation: 'Der Parameter `-H` liefert einen allgemeinen Gesundheitsstatus der Festplatte.' },
  { id: 'lpic2-203-5', topicId: 4, question: 'Wie klonen Sie den gesamten Inhalt einer CD-ROM byte für byte in eine ISO-Imagedatei?', options: ['tar -cvf image.iso /dev/cdrom', 'dd if=/dev/cdrom of=image.iso', 'mkisofs -o image.iso /dev/cdrom', 'cp /dev/cdrom image.iso'], answer: 1, explanation: '`dd` führt eine blockweise Kopie auf niedriger Ebene durch (input file -> output file).' },

  // Topic 204: Advanced Storage
  { id: 'lpic2-204-1', topicId: 5, question: 'Welches Tool wird verwendet, um Software-RAID unter Linux zu erstellen und zu verwalten?', options: ['lvm', 'fdisk', 'mdadm', 'parted'], answer: 2, explanation: '`mdadm` (Multiple Device Admin) ist das primäre Verwaltungswerkzeug für Linux-Software-RAID.' },
  { id: 'lpic2-204-2', topicId: 5, question: 'Welches RAID-Level verwendet reine Datenspiegelung (Data Mirroring) ohne Striping?', options: ['RAID 0', 'RAID 1', 'RAID 5', 'RAID 10'], answer: 1, explanation: 'RAID 1 repliziert exakte Daten auf mehrere Festplatten (Spiegel).' },
  { id: 'lpic2-204-3', topicId: 5, question: 'Welcher LVM-Befehl erweitert eine bestehende Volume Group (VG) um ein neues, initialisiertes physisches Laufwerk?', options: ['pvcreate', 'vgextend', 'lvextend', 'vgcreate'], answer: 1, explanation: '`vgextend` fügt dem VG (Volume Group) ein Physical Volume (PV) hinzu.' },
  { id: 'lpic2-204-4', topicId: 5, question: 'Welcher Parameter in `hdparm` führt rohe Timing-Tests zum Lesen vom Datenträger durch (ohne Puffer)?', options: ['-T', '-S', '-t', '-y'], answer: 2, explanation: '`-t` führt "timing buffered disk reads" durch, eine Leistungsmessung.' },
  { id: 'lpic2-204-5', topicId: 5, question: 'Wofür wird iSCSI hauptsächlich verwendet?', options: ['Web-Firewall', 'Das Kapseln von SCSI-Befehlsprotokollen in Standard-TCP/IP-Paketen', 'Passwörter entschlüsseln', 'Software-Audit-Tool.'], answer: 1, explanation: 'iSCSI überträgt SCSI-Speicherblock-Befehle über TCP/IP-Netzwerke (SANs).' },

  // Topic 205: Network Configuration
  { id: 'lpic2-205-1', topicId: 6, question: 'Welcher Befehl aus dem Paket `iproute2` zeigt den aktuellen ARP-Cache (Nachbarn) an?', options: ['arp -n', 'ip neigh show', 'netstat -rn', 'route -n'], answer: 1, explanation: '`ip neigh show` (oder kurz `ip n`) ersetzt das klassische arp.' },
  { id: 'lpic2-205-2', topicId: 6, question: 'Wie lassen Sie sich die Routing-Tabelle mit der modernen iproute2-Suite anzeigen?', options: ['route', 'ip route show', 'netstat -r', 'ifconfig'], answer: 1, explanation: 'Der Befehl `ip route show` manipuliert und zeigt das IP-Routing an.' },
  { id: 'lpic2-205-3', topicId: 6, question: 'Was bewirkt der Parameter `-c 4` im Befehl `ping`?', options: ['Ping an 4 verschiedene Hosts', 'Nur vier Echo-Anfragen senden und dann stoppen', 'Port 4 pingen', 'IPv6 überprüfen'], answer: 1, explanation: 'Das `-c` steht für Count-Begrenzung.' },
  { id: 'lpic2-205-4', topicId: 6, question: 'Welches Kommandozeilen-Tool wird üblicherweise als Netzwerkpaket-Analyzer (Sniffer) verwendet?', options: ['wireshark', 'nmap', 'tcpdump', 'tracepath'], answer: 2, explanation: 'Der Klassiker `tcpdump` erfasst Netzwerkverkehr direkt aus dem Terminal heraus.' },
  { id: 'lpic2-205-5', topicId: 6, question: 'Über welchen TCP-Port läuft standardmäßig verschlüsseltes HTTPS?', options: ['80', '21', '22', '443'], answer: 3, explanation: 'Standardmäßig empfängt HTTPS (SSL/TLS) auf Port 443.' },

  // Topic 206: System Maintenance
  { id: 'lpic2-206-1', topicId: 7, question: 'Wie lautet die korrekte Reihenfolge, um ein lokales C-Software-Tarball (.tar.gz) zu kompilieren?', options: ['make > make install > ./configure', './configure > make > make install', 'make install > ./configure > make', 'untar > make install > ./configure'], answer: 1, explanation: 'Typischerweise: `./configure` (erstellt Makefiles), `make` (kompiliert), `make install` (installiert).' },
  { id: 'lpic2-206-2', topicId: 7, question: 'Welches Dienstprogramm ist am besten geeignet, um Dateisynchronisation intelligent und effizient (Delta-Übertragung) durchzuführen?', options: ['cp', 'scp', 'ftp', 'rsync'], answer: 3, explanation: 'Rsync verwendet differentielle Delta-Algorithmen, um Dateiübertragungen zu minimieren.' },
  { id: 'lpic2-206-3', topicId: 7, question: 'Was tut der Befehl `strace`?', options: ['Auf Web-Port-Schwachstellen prüfen', 'Systemaufrufe (System Calls) und Signale zwischen Kernel und Anwendung verfolgen', 'Dateisystem scannen', 'Umgebungsvariablen lesen'], answer: 1, explanation: '`strace` (System Trace) überwacht Systemaufrufe (Syscalls) eines Prozesses.' },
  { id: 'lpic2-206-4', topicId: 7, question: 'Welcher Befehl listet alle derzeit geöffneten Dateien (inkl. Sockets) im System auf?', options: ['lsof', 'ps', 'top', 'find'], answer: 0, explanation: '`lsof` steht für "List Open Files" und ist ideal, um blockierte Ressourcen zu identifizieren.' },
  { id: 'lpic2-206-5', topicId: 7, question: 'Mit welchen Standard-Flags extrahiert man üblicherweise ein gz-komprimiertes Archiv (.tar.gz)?', options: ['-cvf', '-xvf', '-zxvf', '-jcvf'], answer: 2, explanation: '-z (gzip dekomprimieren), -x (extrakt), -v (verbose), -f (als Zieldatei anwenden).' },

  // Topic 207: Domain Name Server
  { id: 'lpic2-207-1', topicId: 8, question: 'Welcher Datensatz in BIND DNS ordnet einem Hostnamen (FQDN) ausdrücklich eine IPv4-Adresse zu?', options: ['MX', 'CNAME', 'A', 'AAAA'], answer: 2, explanation: 'Der A-Record (Address).' },
  { id: 'lpic2-207-2', topicId: 8, question: 'Mit welchem Tool überprüfen Sie die Syntax einer Zonendatei in BIND vor dem Neuladen, um Fehler zu vermeiden?', options: ['named-checkconf', 'named-checkzone', 'dns-lint', 'dig'], answer: 1, explanation: 'Der Befehl `named-checkzone` bestätigt die strukturelle Korrektheit ohne Ladevorgang.' },
  { id: 'lpic2-207-3', topicId: 8, question: 'Wofür wird ein MX-Eintrag (Mail Exchange) verwendet?', options: ['Zur Umleitung auf CNAMEs.', 'Weist die verantwortlichen Mailserver zu, die eingehende E-Mails für die Domäne annehmen.', 'Ersetzt DHCP.', 'Zur DDNS-Aktualisierung.'], answer: 1, explanation: 'MX-Records priorisieren den E-Mail-Empfang des MTAs einer Zone.' },
  { id: 'lpic2-207-4', topicId: 8, question: 'Welche kryptografische Erweiterung verhindert Cache-Poisoning bei DNS-Antworten?', options: ['DNS-Over-HTTPS (DoH)', 'TLS', 'DNSSEC', 'TSIG'], answer: 2, explanation: 'DNSSEC verwendet kryptografische Signaturen zur Bekämpfung gefälschter DNS-Antworten.' },
  { id: 'lpic2-207-5', topicId: 8, question: 'Wo befindet sich heutzutage standardmäßig die Hauptkonfigurationsdatei von BIND auf Unix-Systemen?', options: ['/etc/bind/bind.conf', '/etc/named.conf', '/var/named/config', '/etc/resolv.conf'], answer: 1, explanation: '`named` erwartet seine Konventionen vorwiegend unter `/etc/named.conf`.' },

  // Topic 208: Web Services
  { id: 'lpic2-208-1', topicId: 9, question: 'Welche Apache HTTPD-Direktive wird verwendet, um das Hosting mehrerer Websites (Subdomains usw.) auf einem einzigen Server zu kapseln?', options: ['<Directory>', '<ServerHost>', '<VirtualHost>', '<Website>'], answer: 2, explanation: 'Mit dem `<VirtualHost>` Block können Sie isoliert pro Port oder Name hosten.' },
  { id: 'lpic2-208-2', topicId: 9, question: 'Warum wird Nginx in großangelegten Architekturen anderen Lösungen oft vorgezogen?', options: ['Weil Nginx ein lokales LDAP bindet.', 'Aufgrund seiner Event-Based-Struktur, die hocheffizient als Reverse Proxy und Load Balancer agiert.', 'Es blockiert alle Firewalls.', 'Wegen integrierter Datenbanken.'], answer: 1, explanation: 'Nginx hat sich einen Namen als leichtgewichtiger und super-skalierbarer Frontend-Proxy gemacht (Reverse Proxy/Balancing).' },
  { id: 'lpic2-208-3', topicId: 9, question: 'Wie lautet die primäre Funktion des Server-Daemons "Squid" in Unternehmensnetzwerken?', options: ['Relay für FTP-Übertragungen ausführen.', 'Als leistungsstarker Web-Cache-Proxy, der Bandbreite optimiert und Web-Audits generiert.', 'Hypervisor.', 'Mail Delivery.'], answer: 1, explanation: 'Squid puffert (Caches Proxy HTTP/HTTPS) lokale und ausgehende Anfragen zur Leistungsoptimierung des LANs.' },
  { id: 'lpic2-208-4', topicId: 9, question: 'Welches native Apache-Modul verschlüsselt den Datenstrom (TLS), um HTTPS auf Port 443 bereitzustellen?', options: ['mod_rewrite', 'mod_security', 'mod_ssl', 'mod_proxy'], answer: 2, explanation: '`mod_ssl` stellt die Brücke zu den OpenSSL-Bibliotheken her, um die SSL/TLS-Kryptografie einzubinden.' },
  { id: 'lpic2-208-5', topicId: 9, question: 'Auf welchem Standard-TCP-Port empfängt Squid normalerweise Traffic, wenn keine Anpassung vorgenommen wurde?', options: ['80', '443', '3128', '8080'], answer: 2, explanation: 'Die standardmäßige Listening-Socket-Verbindung in Squid ist Port 3128.' },

  // Topic 209: File Sharing
  { id: 'lpic2-209-1', topicId: 10, question: 'Welche Komponente oder Plattform emuliert Microsoft-Netzwerke (SMB/CIFS) brillant in Linux?', options: ['NFS', 'Samba', 'FTP', 'SSHFS'], answer: 1, explanation: 'Samba ermöglicht Linux die Identität innerhalb von AD-Domänen und Windows Dateifreigaben (SMB).' },
  { id: 'lpic2-209-2', topicId: 10, question: 'Unter welchem Pfad liegt die zentrale Konfigurationsdatei für den Samba-Daemon?', options: ['/etc/smb/smb.conf', '/etc/samba/smb.conf', '/usr/local/samba.cfg', '/var/lib/samba/config'], answer: 1, explanation: 'Der Speicherort von globalen Richtlinien ist `/etc/samba/smb.conf`.' },
  { id: 'lpic2-209-3', topicId: 10, question: 'Welche Datei auf dem NFS-Server regelt explizit die Freigaben und Zugriffsrechte für externe Clients?', options: ['/etc/exports', '/etc/nfs.conf', '/etc/fstab', '/etc/samba/smb.conf'], answer: 0, explanation: 'In der Datei `/etc/exports` definiert der Admin NFS-Freigaben und deren Hosts.' },
  { id: 'lpic2-209-4', topicId: 10, question: 'Mit welchem Kommando forcieren Sie NFS, neue Änderungen an Exports "on-the-fly" umzusetzen, ohne Clients rauszuwerfen?', options: ['nfs-update', 'systemctl reload nfs', 'exportfs -a / -r', 'mount -a'], answer: 2, explanation: 'Mittels `exportfs -r` re-parst das System die Exports synchron für aktive User.' },
  { id: 'lpic2-209-5', topicId: 10, question: 'Wie ordnen Sie Ihrem bestehenden Linux-Benutzer ein separates Passwort für den verschlüsselten Windows/Samba-Netzwerkzugriff zu?', options: ['smbpasswd -a', 'useradd', 'passwd', 'pdbedit -n'], answer: 0, explanation: 'Samba-Benutzer müssen über das Tool `smbpasswd -a [user]` zur privaten SAM-Tabelle des Servers hinzugefügt werden.' },

  // Topic 210: Network Client Configuration
  { id: 'lpic2-210-1', topicId: 11, question: 'Welches Protokoll vergibt IP-Leases, Routermasken und DNS-Parameter dynamisch an Hosts im Netzwerk?', options: ['DNS', 'DHCP', 'ARP', 'ICMP'], answer: 1, explanation: 'Dynamic Host Configuration Protocol (DHCP) verwaltet IP-Pools zur automatisierten Konfiguration.' },
  { id: 'lpic2-210-2', topicId: 11, question: 'Was ist der Hauptzweck der Pluggable Authentication Modules (PAM) unter Linux?', options: ['Flexible modulare Authentifizierung für Softwaredienste, wodurch Apps nicht mehr intern kompilierte Anmelderoutinen mitführen müssen.', 'IP-Tabellen filtern.', 'Die Verschlüsselung von Festplatten in /boot erzwingen.', 'Freigaben aus einem Netzwerk mounten.'], answer: 0, explanation: 'PAM trennt Programmlogik von komplexen Überprüfungsverfahren (Local, LDAP, RSA-Token).' },
  { id: 'lpic2-210-3', topicId: 11, question: 'Was ist im Systemadministrativem Sinne die Kernaufgabe von LDAP?', options: ['Ein hierarchischer Netzwerk-Verzeichnisdienst (Directory Services), der Identitätsdaten und Zugriffsrollen anwendungsübergreifend zentralisiert zur Verfügung stellt.', 'Lokale Verwaltung SQL.', 'Linux Domain Authority.', 'Backup der Hosteinträge.'], answer: 0, explanation: 'LDAP (Lightweight Directory Access Protocol) ist ideal zur Abfrage von Telefonbüchern, Personaldatenbaumstrukturen und Single Sign-On Backends.' },
  { id: 'lpic2-210-4', topicId: 11, question: 'In welchem OSI-Status arbeitet eine OpenVPN-Adapterverbindung vom Modell "TUN"?', options: ['Sicherheit auf Hardwareebene.', 'Auf Ebene des IP-Routings (OSI Layer 3 Netzwerk).', 'OSI Layer 2 reines Bridging (MAC).', 'Port Scanning in UDP.'], answer: 1, explanation: 'Ein Tunnel-Interface (TUN) operiert paketorientiert (IP/Layer 3) ohne die Ethernet Header.' },
  { id: 'lpic2-210-5', topicId: 11, question: 'Auf welchem Socket führt OpenVPN ab Werk seine Verbindungen prioritär aus?', options: ['1194 UDP', '22 TCP', '443 TCP', '53 UDP'], answer: 0, explanation: 'OpenVPN nutzt optimalerweise UDP auf Port 1194, um den TCP Meltdown in Tunneln zu vermeiden.' },

  // Topic 211: E-Mail Services
  { id: 'lpic2-211-1', topicId: 12, question: 'Mit welchem Protokoll leiten Mail Transfer Agents (MTA) wie Exim und Postfix von Server zu Server zuverlässig den E-Mail Payload weiter?', options: ['POP3', 'IMAP', 'SMTP', 'SNMP'], answer: 2, explanation: 'Das Simple Mail Transfer Protocol (SMTP, Port 25/587) ist das Backbone des E-Mail-Transports im Internet.' },
  { id: 'lpic2-211-2', topicId: 12, question: 'Welche Konfigurationsdatei regelt primär die Postfix-Instanzen wie Relaying, Einschränkungen und Routing?', options: ['/etc/postfix/master.cf', '/etc/postfix/main.cf', '/etc/mail/sendmail.cf', '/var/spool/postfix/config'], answer: 1, explanation: 'Während `master.cf` die reinen Daemon-Prozesse steuert, liegt die Konfigurationsintelligenz zentriert in der `main.cf`.' },
  { id: 'lpic2-211-3', topicId: 12, question: 'Welcher Dienst fungiert typischerweise als hochmoderner POP3/IMAP Server zum Abrufen der Posteingänge in E-Mail-Clients?', options: ['Postfix', 'Dovecot', 'Procmail', 'Squid'], answer: 1, explanation: 'Dovecot ist das Gegenstück zum MTA; es ruft Nachrichten (Mail Delivery Agent Client) per IMAP asynchron auf mobile Geräte/Endbenutzer ab.' },
  { id: 'lpic2-211-4', topicId: 12, question: 'Wofür eignen sich "Procmail" und "Sieve Scripts" besonders gut?', options: ['Lokale Mails beim Eingang zu filtern, in Unterordner zu verschieben (Postsortierung) oder Logikregeln wie Autoresponder anzuwenden.', 'Als VPN Server fungieren.', 'MTA Caching.', 'DHCP IPs vergeben.'], answer: 0, explanation: 'Beides sind Local Delivery Agents (LDAs), die E-Mails untersuchen und bedingte Sortierregeln (z.B. Spam in Spam-Ordner) ausführen.' },
  { id: 'lpic2-211-5', topicId: 12, question: 'Welcher Kommandofall kompiliert die Liste `/etc/aliases` in eine Hash-Tabelle/Datenbank zur Nutzung durch Postfix/Sendmail?', options: ['makemap', 'newaliases', 'postmap', 'systemctl reload postfix'], answer: 1, explanation: '`newaliases` übersetzt plain-text Aliase dynamisch in `.db` Binary Hash.' },

  // Topic 212: System Security
  { id: 'lpic2-212-1', topicId: 13, question: 'In welcher Table in Iptables finden Manipulationen bezüglich Source-/Destination-Masquerading IP-Rewrites vorzugsweise und aus architektonischen Gründen statt?', options: ['filter', 'mangle', 'nat', 'raw'], answer: 2, explanation: 'Die Tabellensparte `nat` hat spezielle Hooks (Prerouting, Postrouting) exklusiv zum Modifizieren von Source-/Destination IPs.' },
  { id: 'lpic2-212-2', topicId: 13, question: 'Welches Python-Dienstprogramm scannt Logdateien und greift autonom ein, um IPs von wiederholten Brute-Force-Angreifern nach X Versuchen in der Firewall zu blockieren?', options: ['Snort', 'Fail2ban', 'Nmap', 'OpenVAS/Nessus'], answer: 1, explanation: 'Fail2Ban setzt Filterregeln auf Log-Inputs und jailt IP-Adressen für bestimmte Zeit im Firewall.' },
  { id: 'lpic2-212-3', topicId: 13, question: 'Welches Terminalprogramm wird traditionell als "Netzwerkscanner" für aktive Port-Suchen und TCP-Version-Fingerprinting (Reconnaissance) genutzt?', options: ['tcpdump', 'wireshark', 'nmap', 'ping'], answer: 2, explanation: 'Der Network Mapper (NMAP) generiert auf Grundlage von Port Scans extrem treffsichere Maps von offenen Netzwerk-Sockets.' },
  { id: 'lpic2-212-4', topicId: 13, question: 'Was ist im Open-Source-Ökosystem (abgespaltet von Nessus) am ehesten als Vulnerability Assessment Suite bekannt, die Systeme tiefgreifend auf Hunderte offene Lücken (CVEs) prüft und Berichte erstattet?', options: ['Ein einfacher Wrapper.', 'Die Suite OpenVAS von Greenbone.', 'Ein IMAP Scanner.', 'Squid Reverse Proxy.'], answer: 1, explanation: 'OpenVAS testet gezielt auf unsichere Konfigurationen oder Versionsstände pro Host auf Anwendungsebene.' },
  { id: 'lpic2-212-5', topicId: 13, question: 'Mit welchem Kommando ändern Sie in iptables das Verhalten (Policy) der eingehenden Kette so um, dass Traffic standardmäßig sofort und stumm vernichtet wird, falls er keine Ausnahmeregel aufweist?', options: ['iptables -A INPUT -j DROP', 'iptables -P INPUT DROP', 'iptables -I INPUT DROP', 'iptables -D INPUT DROP'], answer: 1, explanation: 'Das Arg `--policy / -P` beschreibt die Standardverhaltensweise (Policy), weshalb ungefilterter Restmüll in Folge verworfen (DROP) wird.' },

  // --- NEUES BATCH 1 (Themen 200-204) ---
  { id: 'lpic2-200-6', topicId: 1, question: 'Was bedeutet die Spalte `wa` in der Ausgabe von `vmstat`?', options: ['Warten auf CPU', 'Warten auf E/A (I/O Wait)', 'Warten auf Netzwerk', 'Warten auf Speicherzuweisung'], answer: 1, explanation: 'Die Spalte `wa` gibt den Prozentsatz der Zeit an, in der die CPU leerlaufend war, während das System ausstehende Festplatten-E/A-Anfragen hatte.' },
  { id: 'lpic2-200-7', topicId: 1, question: 'Welcher Befehl liefert eine schnelle Zusammenfassung der Systemlast-Durchschnitte (Load Averages) für die letzten 1, 5 und 15 Minuten?', options: ['w', 'uptime', 'Beide (A und B)', 'sar'], answer: 2, explanation: 'Sowohl `w` als auch `uptime` zeigen die Load Averages des Systems an.' },
  { id: 'lpic2-200-8', topicId: 1, question: 'Welches ist das primäre Protokoll, das MRTG verwendet, um Daten von Netzwerkgeräten zu sammeln?', options: ['SSH', 'SMTP', 'SNMP', 'HTTP'], answer: 2, explanation: 'MRTG (Multi Router Traffic Grapher) verlässt sich hauptsächlich auf SNMP (Simple Network Management Protocol) zum Sammeln von Metriken.' },
  { id: 'lpic2-200-9', topicId: 1, question: 'Welcher Befehl zeigt Statistiken für Netzwerkschnittstellen an, einschließlich verworfener Pakete und Overrun-Fehler?', options: ['netstat -i', 'netstat -r', 'netstat -tulnp', 'ifconfig -a'], answer: 0, explanation: '`netstat -i` zeigt eine Tabelle aller Netzwerkschnittstellen und deren jeweilige Sende-/Empfangsstatistiken.' },
  { id: 'lpic2-200-10', topicId: 1, question: 'Welcher Speicherwert in der Ausgabe des Befehls `free` ist am aussagekräftigsten dafür, wie viel Speicher für den Start neuer Anwendungen ohne Swapping verfügbar ist?', options: ['total', 'used', 'shared', 'available'], answer: 3, explanation: 'Die Spalte `available` schätzt, wie viel Speicher für den Start neuer Anwendungen ohne Swapping verfügbar ist.' },
  { id: 'lpic2-200-11', topicId: 1, question: 'Wie konfigurieren Sie Collectd, um Metriken über die Zeit effizient zu speichern?', options: ['In CSV-Dateien schreiben', 'Über RRDtool schreiben', 'Nur in MySQL schreiben', 'In syslog schreiben'], answer: 1, explanation: 'Collectd verwendet oft das RRDtool-Plugin (Round Robin Database), um Zeitreihendaten effizient zu speichern.' },
  { id: 'lpic2-200-12', topicId: 1, question: 'Welches Tool ist speziell dafür konzipiert, die E/A-Nutzung pro Prozess in Echtzeit anzuzeigen, ähnlich wie `top`?', options: ['iotop', 'iostat', 'ioping', 'blktrace'], answer: 0, explanation: '`iotop` zeigt eine top-ähnliche Oberfläche mit der Lese- und Schreibbandbreite der E/A pro Prozess an.' },
  { id: 'lpic2-200-13', topicId: 1, question: 'Worauf deuten hohe `si`- und `so`-Werte in `vmstat` stark hin?', options: ['Netzwerküberlastung', 'CPU-Engpass', 'Speichermangel und intensives Swapping', 'Festplattenhardwarefehler'], answer: 2, explanation: 'Hohe Swap-In (`si`) und Swap-Out (`so`) Raten zeigen an, dass das System aufgrund von RAM-Erschöpfung aktiv Speicher auf die Festplatte verschiebt.' },
  { id: 'lpic2-200-14', topicId: 1, question: 'Welcher Befehl listet alle hörenden TCP- und UDP-Sockets zusammen mit der Prozess-ID (PID) auf?', options: ['ss -tulnp', 'netstat -rn', 'ip route', 'arp -a'], answer: 0, explanation: '`ss -tulnp` (oder netstat -tulnp) listet hörende TCP/UDP-Ports und die zugehörigen Prozess-IDs auf.' },
  { id: 'lpic2-200-15', topicId: 1, question: 'Was ist eine "Baseline" in der Kapazitätsplanung?', options: ['Die maximale Kapazität des Servers', 'Der minimale RAM-Bedarf zum Booten', 'Historische Daten, die das normale Systemverhalten repräsentieren', 'Das physische Limit der Netzwerkkarte'], answer: 2, explanation: 'Eine Baseline ist ein bekannter, normaler Zustand des Systems, der über die Zeit aufgezeichnet wurde, um ihn mit Anomalien oder zukünftigem Wachstum zu vergleichen.' },

  { id: 'lpic2-201-6', topicId: 2, question: 'Welcher Befehl reinigt den Kernel-Quellbaum vollständig und entfernt alle kompilierten Dateien sowie die .config-Datei?', options: ['make clean', 'make mrproper', 'make distclean', 'make wipe'], answer: 1, explanation: '`make mrproper` entfernt alle generierten Dateien inklusive der `.config` und diverser Backup-Dateien.' },
  { id: 'lpic2-201-7', topicId: 2, question: 'Was ist der Zweck des Befehls `depmod`?', options: ['Ein Modul entfernen', 'Die Datei modules.dep für modprobe generieren', 'Details über Module anzeigen', 'Module kompilieren'], answer: 1, explanation: '`depmod` analysiert Kernel-Module und erstellt eine Abhängigkeitsliste (`modules.dep`), die von `modprobe` verwendet wird.' },
  { id: 'lpic2-201-8', topicId: 2, question: 'Welches Tool baut Kernel-Module für Drittanbieter-Treiber (wie Nvidia) bei der Installation eines neuen Kernels automatisch neu?', options: ['depmod', 'dracut', 'DKMS', 'kmod'], answer: 2, explanation: 'DKMS (Dynamic Kernel Module Support) ist ein Framework, das externe Kernel-Module neu kompiliert, wenn ein neuer Kernel installiert wird.' },
  { id: 'lpic2-201-9', topicId: 2, question: 'Wie können Sie die aktuell aktive Konfiguration des laufenden Kernels einsehen (sofern vom Kernel unterstützt)?', options: ['cat /proc/kcore', 'zcat /proc/config.gz', 'cat /sys/kernel/config', 'dmesg | grep config'], answer: 1, explanation: 'Falls `IKCONFIG_PROC` aktiviert ist, ist die aktuelle Kernel-Konfiguration über `/proc/config.gz` zugänglich.' },
  { id: 'lpic2-201-10', topicId: 2, question: 'Welcher Befehl listet alle aktuell geladenen Kernel-Module auf?', options: ['lsmod', 'modinfo', 'modprobe -l', 'infomod'], answer: 0, explanation: '`lsmod` formatiert den Inhalt von `/proc/modules`, um zu zeigen, welche Kernel-Module derzeit im Speicher geladen sind.' },
  { id: 'lpic2-201-11', topicId: 2, question: 'Was ist der Hauptunterschied zwischen `initrd` und `initramfs`?', options: ['initrd ist ein cpio-Archiv; initramfs ist ein Blockgerät-Image', 'initramfs ist ein cpio-Archiv, das in ein tmpfs entpackt wird; initrd ist ein Blockgerät-Image', 'initrd ist nur für UEFI', 'initramfs kann keine Module laden'], answer: 1, explanation: '`initramfs` ist ein modernerer Ansatz, der ein komprimiertes cpio-Archiv verwendet, das in ein tmpfs geladen wird.' },
  { id: 'lpic2-201-12', topicId: 2, question: 'Welcher Befehl zeigt Informationen über ein Kernel-Modul an, wie Autor, Beschreibung und akzeptierte Parameter?', options: ['lsmod', 'modprobe -d', 'modinfo', 'insmod -i'], answer: 2, explanation: '`modinfo` extrahiert und zeigt Informationen aus der Objektdatei des Moduls selbst an.' },
  { id: 'lpic2-201-13', topicId: 2, question: 'Welcher Befehl liest `sysctl.conf` und wendet die Kernel-Parameter sofort an?', options: ['sysctl -w', 'sysctl -a', 'sysctl -p', 'sysctl -r'], answer: 2, explanation: '`sysctl -p` lädt Einstellungen aus `/etc/sysctl.conf` (oder einer angegebenen Datei) in den laufenden Kernel.' },
  { id: 'lpic2-201-14', topicId: 2, question: 'Wo sucht `udev` nach benutzerdefinierten Regeln für Hardware-Ereignisse?', options: ['/etc/udev/rules.d/', '/lib/udev/rules.d/', 'Beide (A und B)', '/var/run/udev/'], answer: 2, explanation: '`udev` liest Standardregeln unter `/lib/udev/rules.d/` und benutzerdefinierte Admin-Regeln unter `/etc/udev/rules.d/`.' },
  { id: 'lpic2-201-15', topicId: 2, question: 'Welcher Befehl entfernt ein laufendes Kernel-Modul, sofern es nicht mehr in Gebrauch ist?', options: ['rmmod', 'insmod -r', 'modprobe -r', 'Beide (A und C)'], answer: 3, explanation: 'Sowohl `rmmod` als auch `modprobe -r` können zum Entfernen von Modulen verwendet werden; `modprobe -r` entfernt auch Abhängigkeiten sauber.' },

  { id: 'lpic2-202-6', topicId: 3, question: 'Welcher Befehl setzt unter systemd das Standard-Target auf Grafisch (entspricht Runlevel 5)?', options: ['systemctl set-default graphical.target', 'systemctl isolate graphical.target', 'systemctl default graphical.target', 'ln -s /lib/systemd/system/graphical.target /etc/inittab'], answer: 0, explanation: '`systemctl set-default` ändert das Standard-Boot-Target, indem es den symbolischen Link `/etc/systemd/system/default.target` aktualisiert.' },
  { id: 'lpic2-202-7', topicId: 3, question: 'Welche Taste ermöglicht es beim Start von GRUB 2 normalerweise, das Boot-Menü aufzurufen, um Kernel-Parameter zu bearbeiten, falls es versteckt ist?', options: ['F8', 'F12', 'Shift oder Esc', 'Enter'], answer: 2, explanation: 'Das Halten von `Shift` (BIOS-Systeme) oder das Drücken von `Esc` (UEFI-Systeme) unterbricht den GRUB 2 Start und zeigt das Menü an.' },
  { id: 'lpic2-202-8', topicId: 3, question: 'Was bewirkt der Befehl `systemctl isolate`?', options: ['Startet das System neu', 'Wechselt den aktuellen Betriebszustand in ein neues Target und stoppt nicht benötigte Dienste', 'Deaktiviert Netzwerk-Schnittstellen', 'Führt ein chroot in eine andere Umgebung aus'], answer: 1, explanation: '`isolate` wechselt das System sofort in ein neues Target (ähnlich wie ein Runlevel-Wechsel unter SysV).' },
  { id: 'lpic2-202-9', topicId: 3, question: 'Welche Datei enthält globale Einstellungen (wie Timeout und Standardeintrag), die von `grub-mkconfig` zur Generierung der GRUB 2 Konfiguration verwendet werden?', options: ['/etc/grub.d/00_header', '/boot/grub/grub.cfg', '/etc/default/grub', '/boot/grub/menu.lst'], answer: 2, explanation: '`/etc/default/grub` enthält Variablen wie `GRUB_TIMEOUT` und `GRUB_CMDLINE_LINUX`, welche die Dateigenerierung steuern.' },
  { id: 'lpic2-202-10', topicId: 3, question: 'Was ist PXE?', options: ['Ein Partitionstabellenformat', 'Eine Methode zum Booten eines Betriebssystems über das Netzwerk mittels DHCP und TFTP', 'Ein Linux-Bootloader für ARM', 'Ein systemd-Unit-Typ'], answer: 1, explanation: 'Das Preboot eXecution Environment (PXE) ermöglicht es Netzwerkkarten, einen Bootloader und Kernel von einem Netzwerk-Server zu beziehen.' },
  { id: 'lpic2-202-11', topicId: 3, question: 'Welches Verzeichnis enthält die modularen Skripte, die von `grub-mkconfig` ausgeführt werden?', options: ['/etc/default/grub', '/etc/grub.d/', '/boot/grub/scripts/', '/lib/grub/'], answer: 1, explanation: 'Das Verzeichnis `/etc/grub.d/` enthält ausführbare Skripte (wie 10_linux), die das System während der Generierung von grub.cfg scannen.' },
  { id: 'lpic2-202-12', topicId: 3, question: 'Was ist `systemd-boot`?', options: ['Ein SysVinit-Wrapper', 'Ein leichtgewichtiger UEFI-Bootmanager', 'Ein Plugin für GRUB', 'Ein Plymouth-Theme'], answer: 1, explanation: '`systemd-boot` (früher gummiboot) ist ein einfacher UEFI-Bootmanager, der in systemd integriert ist.' },
  { id: 'lpic2-202-13', topicId: 3, question: 'Welchen Kernel-Parameter können Sie in GRUB übergeben, um die Authentifizierung zu umgehen, falls Sie Ihr Root-Passwort vergessen haben?', options: ['root=/dev/null', 'init=/bin/bash', 'skip_auth=1', 'runlevel=0'], answer: 1, explanation: 'Das Hinzufügen von `init=/bin/bash` (oder /bin/sh) mountet Root und startet sofort eine Root-Shell ohne Passwortabfrage.' },
  { id: 'lpic2-202-14', topicId: 3, question: 'Welcher Befehl generiert auf Red Hat / CentOS Systemen eine initiale RAM-Disk (initramfs)?', options: ['mkinitcpio', 'mkinitrd / dracut', 'update-initramfs', 'initramfs-build'], answer: 1, explanation: 'RHEL-basierte Systeme verwendeten historisch `mkinitrd` und nutzen nun nativ `dracut` zum Erstellen des initramfs.' },
  { id: 'lpic2-202-15', topicId: 3, question: 'Welches Skript ist unter SysVinit typischerweise für die Ausführung der rc-Skripte für den definierten Runlevel verantwortlich?', options: ['/etc/rc.local', '/etc/init.d/rc', '/sbin/runlevel', '/bin/sh'], answer: 1, explanation: 'Das Skript `/etc/init.d/rc` wird von init mit dem Runlevel als Argument aufgerufen, um entsprechende Dienste in `/etc/rcX.d/` zu starten/stoppen.' },

  { id: 'lpic2-203-6', topicId: 4, question: 'Welcher Befehl zeigt die Hardware-Geometrie und Partitionen einer Festplatte an?', options: ['df -h', 'lsblk', 'fdisk -l', 'Beide (B und C)'], answer: 3, explanation: 'Sowohl `lsblk` als auch `fdisk -l` beschreiben Blockgeräte und Partitionen (fdisk zeigt Geometriedetails).' },
  { id: 'lpic2-203-7', topicId: 4, question: 'Welcher Befehl konvertiert ein ext3-Dateisystem ohne Datenverlust nach ext4?', options: ['tune2fs -O extents,uninit_bg,dir_index /dev/sda1', 'mkfs.ext4 /dev/sda1', 'fsck.ext4 -y /dev/sda1', 'parted /dev/sda1 convert ext4'], answer: 0, explanation: '`tune2fs` ermöglicht das Aktivieren von Dateisystemfunktionen auf einem bestehenden Laufwerk; das Hinzufügen der ext4-Funktionen konvertiert es effektiv.' },
  { id: 'lpic2-203-8', topicId: 4, question: 'Welches Werkzeug ändert die UUID eines ext2/ext3/ext4-Dateisystems?', options: ['uuidgen', 'blkid', 'tune2fs -U', 'xfs_admin'], answer: 2, explanation: '`tune2fs -U [UUID|random] /dev/sdX` ändert die UUID des Dateisystems auf ext-Systemen.' },
  { id: 'lpic2-203-9', topicId: 4, question: 'Welche Option in `/etc/fstab` mountet das Dateisystem im Nur-Lese-Modus?', options: ['rw', 'ro', 'noexec', 'nosuid'], answer: 1, explanation: 'Die Option `ro` steht für Read-Only.' },
  { id: 'lpic2-203-10', topicId: 4, question: 'Welcher Befehl liefert Informationen über den Status und die Fragmentierung eines XFS-Dateisystems?', options: ['xfs_repair', 'xfs_info', 'xfs_db', 'Keine der oben genannten'], answer: 1, explanation: '`xfs_info` zeigt Details zur Geometrie und zum Layout eines gemounteten XFS-Dateisystems an.' },
  { id: 'lpic2-203-11', topicId: 4, question: 'Wie können Sie eine Festplatte (/dev/sdb) sicher löschen, indem Sie sie mit Zufallsdaten überschreiben?', options: ['dd if=/dev/urandom of=/dev/sdb bs=1M', 'rm -rf /dev/sdb', 'mkfs.ext4 /dev/sdb', 'fdisk -w /dev/sdb'], answer: 0, explanation: 'Die Verwendung von `dd` zum Lesen von `/dev/urandom` überschreibt das Ziellaufwerk physisch mit unvorhersehbaren binären Daten.' },
  { id: 'lpic2-203-12', topicId: 4, question: 'Was bewirkt der Befehl `badblocks`?', options: ['Formatiert die Festplatte', 'Sucht nach physisch beschädigten Sektoren auf einem Gerät', 'Repariert das Dateisystem-Journal', 'Identifiziert defekten RAM'], answer: 1, explanation: '`badblocks` führt Lese-/Schreibtests auf Sektoren durch, um physisch unbrauchbare Blöcke auf dem Speichermedium zu identifizieren.' },
  { id: 'lpic2-203-13', topicId: 4, question: 'Welcher Btrfs-Befehl erstellt einen beschreibbaren Snapshot eines Subvolumes?', options: ['btrfs subvolume snapshot', 'btrfs snap create', 'lvcreate -s', 'btrfs-image'], answer: 0, explanation: '`btrfs subvolume snapshot <source> <dest>` erstellt einen Copy-on-Write-Snapshot.' },
  { id: 'lpic2-203-14', topicId: 4, question: 'Was ist `autofs`?', options: ['Ein Tool zum Formatieren von Festplatten', 'Ein Daemon, der Dateisysteme bei Bedarf automatisch mountet', 'Ein Ersatz für GRUB', 'Ein Netzwerkpaket-Router'], answer: 1, explanation: '`autofs` ermöglicht automatisches Einbinden (nur mounten, wenn ein Benutzer auf ein bestimmtes Verzeichnis zugreift) und automatisches Aushängen.' },
  { id: 'lpic2-203-15', topicId: 4, question: 'Welcher Befehl zur Erstellung optischer Medien erstellt ein ISO9660-Dateisystemabbild?', options: ['cdrecord', 'mkisofs', 'growisofs', 'wodim'], answer: 1, explanation: '`mkisofs` (oder genisoimage) nimmt einen Verzeichnisbaum und generiert eine ISO9660-Layoutdatei zum Brennen.' },

  { id: 'lpic2-204-6', topicId: 5, question: 'Wie verringern Sie unter LVM sicher die Größe eines Logical Volumes?', options: ['lvresize -L -10G /dev/vg/lv', 'Zuerst das Dateisystem im LV verkleinern, dann das LV verkleinern', 'Zuerst das LV verkleinern, dann das Dateisystem verkleinern', 'Ein LV kann nicht verkleinert werden'], answer: 1, explanation: 'Man muss das Dateisystem (z. B. resize2fs) VOR dem Verkleinern des LV schrumpfen, um Datenverlust an den Grenzen zu vermeiden.' },
  { id: 'lpic2-204-7', topicId: 5, question: 'Was passiert bei der Verwaltung eines Software-RAID 5 Arrays mit `mdadm`, wenn eine Festplatte ausfällt?', options: ['Daten sind dauerhaft verloren', 'Das Array läuft im degradierten Modus weiter und nutzt Parität zur Berechnung fehlender Daten', 'Das System erleidet sofort eine Kernel Panic', 'Das Array wechselt zu RAID 0'], answer: 1, explanation: 'RAID 5 kann genau einen Festplattenausfall tolerieren und läuft im "degradierten Modus" bis zum Rebuild weiter.' },
  { id: 'lpic2-204-8', topicId: 5, question: 'Welcher Befehl initiiert eine iSCSI-Sitzung, um Ziele (Targets) auf einem Server zu finden?', options: ['iscsiadm -m discovery -t sendtargets -p <IP>', 'iscsid --scan', 'mount -t iscsi', 'lvscan'], answer: 0, explanation: '`iscsiadm` ist das Kommandozeilen-Tool zur Interaktion mit dem Open-iSCSI-Initiator für Discovery und Login.' },
  { id: 'lpic2-204-9', topicId: 5, question: 'Was zeigt der LVM-Befehl `vgdisplay` an?', options: ['Nur physische Volumes', 'Nur logische Volumes', 'Attribute der Volume Group wie Gesamtgröße, freie PEs und zugewiesene PEs', 'Dateisystem-UUIDs'], answer: 2, explanation: '`vgdisplay` liefert Metadaten über Volume Groups, einschließlich Details zur Kapazität der Physical Extents (PE).' },
  { id: 'lpic2-204-10', topicId: 5, question: 'Wie fügen Sie einem bestehenden `mdadm` RAID-Array (/dev/md0) eine Ersatzfestplatte (Spare) hinzu?', options: ['mdadm --add /dev/md0 /dev/sdX', 'mdadm --grow /dev/md0 --size=spare', 'mdadm --create /dev/md0 /dev/sdX', 'Man kann aktiven Arrays keine Spares hinzufügen'], answer: 0, explanation: 'Die Option `--add` (oder `-a`) fügt einem bestehenden Array im laufenden Betrieb ein Ersatzgerät hinzu.' },
  { id: 'lpic2-204-11', topicId: 5, question: 'Was ist der Zweck von LVM-Snapshots?', options: ['Permanente Backups auf Band erstellen', 'Den Zustand eines Logical Volumes sofort erfassen (Copy-on-Write) für konsistente Backups', 'Festplattenlesevorgänge beschleunigen', 'ext4 nach xfs konvertieren'], answer: 1, explanation: 'Snapshots verfolgen Änderungen via CoW, wodurch ein zeitlich fixierter Zustand eines Volumes ohne Dienstunterbrechung gesichert werden kann.' },
  { id: 'lpic2-204-12', topicId: 5, question: 'Was ist in einer iSCSI-Umgebung ein IQN?', options: ['Internal Query Network', 'iSCSI Qualified Name', 'Internet Quota Node', 'Initial Queue Number'], answer: 1, explanation: 'Der iSCSI Qualified Name (IQN) ist ein weltweit eindeutiger Identifikator für Initiatoren und Targets.' },
  { id: 'lpic2-204-13', topicId: 5, question: 'Welche `hdparm`-Option ruft das Spindown-Timeout einer Festplatte ab oder legt es fest?', options: ['-S', '-y', '-Z', '-B'], answer: 0, explanation: '`hdparm -S` legt den Timeout vor dem Stillsetzen der Platten (Spindown) für eine IDE/SATA/SAS-Platte fest.' },
  { id: 'lpic2-204-14', topicId: 5, question: 'Welche Datei speichert den Status und Details von `mdadm` Software-RAID-Arrays dynamisch?', options: ['/etc/mdadm.conf', '/proc/mdstat', '/var/log/raid.log', '/sys/block/raid'], answer: 1, explanation: '`/proc/mdstat` bietet eine Echtzeit-Zusammenfassung der Software-RAID-Arrays des Kernels und deren Synchronisationsstatus.' },
  { id: 'lpic2-204-15', topicId: 5, question: 'Welche LVM-Komponente wird direkt auf einer rohen Festplattenpartition erstellt?', options: ['Logical Volume (LV)', 'Volume Group (VG)', 'Physical Volume (PV)', 'Volume Extent (VE)'], answer: 2, explanation: 'Ein Physical Volume (PV) ist die Basis-LVM-Struktur, die direkt auf einer Festplatte oder Partition erstellt wird.' },

  // --- NEUES BATCH 2 (Themen 205-209) ---
  { id: 'lpic2-205-6', topicId: 6, question: 'Mit welcher Option zeigt `ip addr` nur die IPv4-Schnittstelleninformationen an?', options: ['-4', '-v4', '--ipv4', 'Beide (A und C)'], answer: 3, explanation: 'Sowohl `-4` als auch `--ipv4` filtern die Ausgabe von `ip addr`, um nur IPv4-Informationen anzuzeigen.' },
  { id: 'lpic2-205-7', topicId: 6, question: 'Welcher Befehl wird verwendet, um eine Netzwerkschnittstelle unter Verwendung der klassischen `ifupdown`-Suite sofort zu deaktivieren?', options: ['ifconfig eth0 down', 'ip link set eth0 down', 'ifdown eth0', 'netstop eth0'], answer: 2, explanation: '`ifdown` ist das Skript auf hoher Ebene, das die Schnittstelle stoppt und die Konfigurationsprofile bereinigt.' },
  { id: 'lpic2-205-8', topicId: 6, question: 'Welches Tool bietet eine interaktive "Top"-ähnliche Ansicht der Bandbreitennutzung pro Host in einem Netzwerk?', options: ['iftop', 'nload', 'bmon', 'nmap'], answer: 0, explanation: '`iftop` hört auf den Netzwerkverkehr einer Schnittstelle und zeigt eine Tabelle der aktuellen Bandbreitennutzung nach Host-Paaren an.' },
  { id: 'lpic2-205-9', topicId: 6, question: 'Wofür wird das Tool `ethtool` hauptsächlich verwendet?', options: ['Firewall-Regeln konfigurieren', 'Abfrage und Steuerung von Netzwerktreiber- und Hardwareeinstellungen (wie Speed/Duplex)', 'IP-Statistiken anzeigen', 'Webserver-Lasttests'], answer: 1, explanation: '`ethtool` wird verwendet, um Parameter wie Ethernet-Geschwindigkeit, Autonegotiation und Checksum-Offloading zu untersuchen und zu ändern.' },
  { id: 'lpic2-205-10', topicId: 6, question: 'Welche Datei wird verwendet, um DNS-Nameserver-IPs für das System manuell zu konfigurieren?', options: ['/etc/hosts', '/etc/resolv.conf', '/etc/networks', '/etc/hostname'], answer: 1, explanation: '`/etc/resolv.conf` ist die Standarddatei, die vom Resolver verwendet wird, um Nameserver-Abfragen zu steuern.' },
  { id: 'lpic2-205-11', topicId: 6, question: 'Zweck von `nc` (Netcat)?', options: ['Ein grafischer Browser', 'Ein vielseitiges Hilfsprogramm zum Lesen und Schreiben von Daten über Netzwerkverbindungen (TCP/UDP)', 'Ein Passwort-Cracker', 'Ein Kernel-Modul-Manager'], answer: 1, explanation: 'Netcat ("Schweizer Taschenmesser") kann Sockets erstellen, Ports scannen und Daten über das Netzwerk übertragen.' },
  { id: 'lpic2-205-12', topicId: 6, question: 'Welcher Befehl zeigt die Route an, die Pakete nehmen, um einen Host zu erreichen, indem er ICMP oder UDP-Time-to-Live (TTL) verwendet?', options: ['tracepath', 'traceroute', 'route-trace', 'Beide (A und B)'], answer: 3, explanation: 'Sowohl `traceroute` als auch `tracepath` verfolgen den Pfad zu einem Netzwerk-Host.' },
  { id: 'lpic2-205-13', topicId: 6, question: 'Welchen Port nutzt SSH standardmäßig?', options: ['20', '21', '22', '23'], answer: 2, explanation: 'SSH (Secure Shell) verwendet standardmäßig den TCP-Port 22.' },
  { id: 'lpic2-205-14', topicId: 6, question: 'Was tut der Befehl `ss -tulpn`?', options: ['Das System neu starten', 'Alle hörenden TCP/UDP-Sockets mit Prozessnamen/PIDs anzeigen', 'Passwort-Hashes scannen', 'Routing-Tabellen löschen'], answer: 1, explanation: '`-t` (tcp), `-u` (udp), `-l` (listening), `-p` (processes), `-n` (numeric).' },
  { id: 'lpic2-205-15', topicId: 6, question: 'Wie weisen Sie einer Schnittstelle (eth0) temporär eine IP-Adresse (192.168.1.50/24) mit dem `ip`-Befehl zu?', options: ['ip addr add 192.168.1.50/24 dev eth0', 'ifconfig eth0 192.168.1.50', 'ip link eth0 set addr 192.168.1.50', 'netcfg eth0 192.168.1.50'], answer: 0, explanation: 'Der Befehl `ip addr add` wird verwendet, um neue Adressen zu Schnittstellen hinzuzufügen.' },

  { id: 'lpic2-206-6', topicId: 7, question: 'Welcher `rsync`-Schalter aktiviert den "Archive"-Modus (der Berechtigungen, Symlinks und Zeitstempel beibehält)?', options: ['-r', '-v', '-a', '-z'], answer: 2, explanation: '`-a` (Archive) ist eine Kombination aus -rlptgoD und wird für Backups empfohlen.' },
  { id: 'lpic2-206-7', topicId: 7, question: 'Sie müssen einen Patch auf einen Quellcode-Ordner anwenden. Welchen Befehl verwenden Sie?', options: ['diff', 'patch', 'apply', 'update'], answer: 1, explanation: 'Der Befehl `patch` nimmt eine von `diff` erzeugte Datei und wendet die Änderungen auf die Originaldateien an.' },
  { id: 'lpic2-206-8', topicId: 7, question: 'Was ist der Zweck des Befehls `ldd`?', options: ['Treiber laden', 'Abhängigkeiten von gemeinsam genutzten Bibliotheken (shared libraries) einer Binärdatei anzeigen', 'Hardware-Fehler erkennen', 'Festplattenpartitionen auflisten'], answer: 1, explanation: '`ldd` druckt die von einem Programm benötigten Shared Libraries aus.' },
  { id: 'lpic2-206-9', topicId: 7, question: 'Welcher `tar`-Parameter wird verwendet, um ein Archiv mit bzip2-Kompression (.tar.bz2) zu erstellen?', options: ['-z', '-j', '-J', '-b'], answer: 1, explanation: '`-j` filtert das Archiv durch bzip2.' },
  { id: 'lpic2-206-10', topicId: 7, question: 'Wo werden die von Benutzern kompilierten Programme standardmäßig installiert, wenn kein Präfix angegeben ist?', options: ['/bin', '/usr/bin', '/usr/local/bin', '/opt'], answer: 2, explanation: 'In der GNU-Etikette ist `/usr/local/` für Software vorgesehen, die nicht vom Paketmanager der Distribution verwaltet wird.' },
  { id: 'lpic2-206-11', topicId: 7, question: 'Welcher Befehl wird verwendet, um nach Dateien mit gesetztem SUID-Bit zu suchen?', options: ['find / -perm -4000', 'ls -s', 'chkconfig --list', 'grep suid /etc/*'], answer: 0, explanation: '`find` mit `-perm -4000` sucht nach Dateien, bei denen mindestens das SUID-Bit gesetzt ist.' },
  { id: 'lpic2-206-12', topicId: 7, question: 'Zweck von `make`?', options: ['Backup erstellen', 'Die Kompilation und das Linken von Programmen basierend auf einem Makefile automatisieren', 'Internetverbindung herstellen', 'Partitionstabellen bearbeiten'], answer: 1, explanation: '`make` verfolgt Abhängigkeiten und kompiliert nur geänderte Dateien neu.' },
  { id: 'lpic2-206-13', topicId: 7, question: 'Welches Kommandozeilenwerkzeug wird verwendet, um installierte Pakete auf einem Debian-basierten System aufzulisten?', options: ['rpm -qa', 'dpkg -l', 'apt list', 'Beide (B und C)'], answer: 3, explanation: 'Sowohl `dpkg -l` als auch `apt list` erfüllen diesen Zweck.' },
  { id: 'lpic2-206-14', topicId: 7, question: 'Welchen Befehl verwenden Sie, um ein Patch-File aus zwei Dateien (alt und neu) zu erstellen?', options: ['patch old new > file.patch', 'diff -u old new > file.patch', 'cmp old new', 'grep -d old new'], answer: 1, explanation: '`diff -u` (Unified Format) ist das Standardformat für die Erstellung von Patches.' },
  { id: 'lpic2-206-15', topicId: 7, question: 'Welcher Befehl zeigt die letzten 20 Zeilen einer Logdatei an und verfolgt neue Einträge in Echtzeit?', options: ['head -n 20 -f', 'tail -n 20 -f', 'less +G', 'watch logfile'], answer: 1, explanation: '`tail -f` (follow) ist essentiell für die Live-Überwachung von Logs.' },

  { id: 'lpic2-207-6', topicId: 8, question: 'Welcher BIND-Dateityp ordnet IP-Adressen Hostnamen zu (Reverse Lookup)?', options: ['A-Zone', 'PTR-Zone', 'CNAME-Zone', 'MX-Zone'], answer: 1, explanation: 'PTR-Records (Pointer) werden in Reverse-Lookup-Zonen verwendet.' },
  { id: 'lpic2-207-7', topicId: 8, question: 'Was ist die Funktion des "Serial"-Wertes in einem SOA-Eintrag (Start of Authority)?', options: ['Die IP-Adresse des Masters', 'Eine Versionsnummer; Slaves prüfen diesen Wert, um zu entscheiden, ob sie einen Zonentransfer durchführen müssen', 'Die Seriennummer der Hardware', 'Die TTL der Zone'], answer: 1, explanation: 'Wenn der Serial-Wert auf dem Master erhöht wird, wissen die Slaves, dass die Zone aktualisiert wurde.' },
  { id: 'lpic2-207-8', topicId: 8, question: 'Welcher Port wird standardmäßig für Zonentransfers (AXFR/IXFR) zwischen Master und Slave DNS-Servern verwendet?', options: ['53 UDP', '53 TCP', '5353 UDP', '953 TCP'], answer: 1, explanation: 'Während normale Abfragen meist UDP nutzen, verwenden Zonentransfers aufgrund der Datenmenge TCP Port 53.' },
  { id: 'lpic2-207-9', topicId: 8, question: 'Was ist der Zweck der Option `forwarders` in `named.conf`?', options: ['Abfragen an einen anderen DNS-Server weiterleiten, falls der lokale Server nicht autoritativ ist und keine Daten im Cache hat', 'Den Server zum Master machen', 'Zonentransfers verbieten', 'IPv6 aktivieren'], answer: 0, explanation: 'Forwarder werden oft verwendet, um DNS-Abfragen an einen Resolver des ISPs oder einen öffentlichen Resolver wie 8.8.8.8 zu senden.' },
  { id: 'lpic2-207-10', topicId: 8, question: 'Welcher Befehl wird verwendet, um eine DNS-Zone von einem Master-Server manuell auf den lokalen Rechner anzufordern (Zonentransfer-Test)?', options: ['dig @server domain AXFR', 'nslookup domain', 'host -l domain server', 'Beide (A und C)'], answer: 3, explanation: 'Sowohl `dig` mit `AXFR` als auch `host -l` versuchen einen vollen Zonentransfer.' },
  { id: 'lpic2-207-11', topicId: 8, question: 'Welcher Typ von Nameserver speichert keine Zonendateien dauerhaft, sondern liefert nur Antworten aus seinem Cache aus?', options: ['Master Server', 'Slave Server', 'Caching-Only Server', 'Root Server'], answer: 2, explanation: 'Ein Caching-Only Server ist nicht autoritativ für Zonen, spart aber Bandbreite durch Zwischenspeicherung.' },
  { id: 'lpic2-207-12', topicId: 8, question: 'Was definiert der "Refresh"-Wert im SOA-Eintrag?', options: ['Wie oft der Client den Cache leert', 'Wie oft ein Slave-Server den Master auf Zonen-Updates prüfen soll', 'Wie lange der DNS-Dienst läuft', 'Die Zeit bis zum Booten'], answer: 1, explanation: 'Der Refresh-Intervall sagt den Slaves, in welchen Abständen sie beim Master nach einer neuen Serial fragen sollen.' },
  { id: 'lpic2-207-13', topicId: 8, question: 'Zweck von RNDC?', options: ['Zonentransfers verschlüsseln', 'Remote Name Daemon Control; ermöglicht die Verwaltung von BIND (Reload, Stats) über das Netzwerk', 'DNS-Einträge automatisch erstellen', 'Hardware-Fehler im RAM erkennen'], answer: 1, explanation: 'RNDC ist das Standard-Tool zur Fernverwaltung und Steuerung von `named`.' },
  { id: 'lpic2-207-14', topicId: 8, question: 'Welcher DNS-Eintragstyp ordnet einen Namen einem anderen Namen (Alias) zu?', options: ['A', 'NS', 'CNAME', 'TXT'], answer: 2, explanation: 'CNAME (Canonical Name) wird verwendet, um einen Alias für einen bestehenden A-Eintrag zu erstellen.' },
  { id: 'lpic2-207-15', topicId: 8, question: 'In welcher Datei unter `/etc` konfigurieren Sie die Reihenfolge der Namensauflösung (z.B. erst Files, dann DNS)?', options: ['/etc/resolv.conf', '/etc/nsswitch.conf', '/etc/hosts', '/etc/bind/named.conf'], answer: 1, explanation: 'In `/etc/nsswitch.conf` definiert die Zeile `hosts: files dns`, dass zuerst in `/etc/hosts` gesucht wird.' },

  { id: 'lpic2-208-6', topicId: 9, question: 'Welche Apache-Direktive definiert das Wurzelverzeichnis, aus dem Dateien für eine Website ausgeliefert werden?', options: ['RootDirectory', 'DocumentRoot', 'WebBase', 'HomePath'], answer: 1, explanation: '`DocumentRoot` legt den Pfad im Dateisystem fest, der als `/` der Website erscheint.' },
  { id: 'lpic2-208-7', topicId: 9, question: 'Welcher Befehl prüft die Apache-Konfigurationssyntax auf Fehler?', options: ['apachectl configtest', 'httpd -t', 'Beide (A und B)', 'service httpd check'], answer: 2, explanation: 'Sowohl `apachectl configtest` als auch `httpd -t` validieren die Syntax vor einem Neustart.' },
  { id: 'lpic2-208-8', topicId: 9, question: 'Wie aktivieren Sie ein Apache-Modul auf einem Debian-System?', options: ['modenable name', 'a2enmod name', 'apache-mod-on name', 'edit httpd.conf'], answer: 1, explanation: '`a2enmod` (Apache2 Enable Module) erstellt die notwendigen Symlinks in `/etc/apache2/mods-enabled/`.' },
  { id: 'lpic2-208-9', topicId: 9, question: 'Was ist der Hauptzweck von Nginx "FastCGI"?', options: ['Dateien schneller hochladen', 'Kommunikation mit externen Applikations-Servern (wie PHP-FPM) zur Verarbeitung dynamischer Inhalte', 'Bilder komprimieren', 'SSL-Zertifikate generieren'], answer: 1, explanation: 'Nginx liefert selbst kein PHP aus; es leitet Anfragen über FastCGI an einen Interpreter wie PHP-FPM weiter.' },
  { id: 'lpic2-208-10', topicId: 9, question: 'Welches Apache-Modul ermöglicht URL-Umschreibungen (Rewriting) und Umleitungen basierend auf Regeln?', options: ['mod_redirect', 'mod_rewrite', 'mod_alias', 'mod_proxy'], answer: 1, explanation: '`mod_rewrite` ist das mächtige Modul zur Manipulation von URLs mittels regulärer Ausdrücke.' },
  { id: 'lpic2-208-11', topicId: 9, question: 'In welcher Nginx-Konfigurationsdatei werden die Server-Blöcke (Virtual Hosts) üblicherweise definiert?', options: ['/etc/nginx/nginx.conf', '/etc/nginx/sites-available/', 'Beide (A und B)', '/var/www/vhosts/'], answer: 2, explanation: 'Nginx nutzt oft eine modulare Konfiguration mit `include`-Anweisungen in der Hauptdatei.' },
  { id: 'lpic2-208-12', topicId: 9, question: 'Was bewirkt die Direktive `AllowOverride All` in Apache?', options: ['Erlaubt allen Benutzern den Zugriff', 'Erlaubt die Verwendung von `.htaccess`-Dateien zur Überschreibung der globalen Konfiguration in diesem Verzeichnis', 'Deaktiviert die Firewall', 'Erzwingt HTTPS'], answer: 1, explanation: '`AllowOverride` steuert, welche Direktiven in `.htaccess`-Dateien deklariert werden dürfen.' },
  { id: 'lpic2-208-13', topicId: 9, question: 'Welcher HTTP-Statuscode bedeutet "Nicht gefunden" (Not Found)?', options: ['200', '301', '403', '404'], answer: 3, explanation: '404 ist der Standardcode, wenn die angeforderte Ressource auf dem Server nicht existiert.' },
  { id: 'lpic2-208-14', topicId: 9, question: 'Zweck von SNI (Server Name Indication)?', options: ['Passwörter speichern', 'Mehrere SSL-Zertifikate auf einer einzigen IP-Adresse hosten', 'DNS-Einträge beschleunigen', 'Datenbanken sichern'], answer: 1, explanation: 'SNI sendet den Hostnamen während des TLS-Handshakes, damit der Server das richtige Zertifikat auswählen kann.' },
  { id: 'lpic2-208-15', topicId: 9, question: 'Welcher Port wird standardmäßig für HTTP (unverschlüsselt) verwendet?', options: ['21', '80', '443', '8080'], answer: 1, explanation: 'HTTP nutzt standardmäßig den TCP-Port 80.' },

  { id: 'lpic2-209-6', topicId: 10, question: 'Welche Option in `/etc/exports` erlaubt es dem NFS-Server, Schreibvorgänge erst zu bestätigen, wenn die Daten physisch auf dem Datenträger gespeichert sind (sicherer)?', options: ['async', 'sync', 'secure', 'no_wdelay'], answer: 1, explanation: '`sync` (Standard in moderneren Versionen) garantiert Datenintegrität bei Abstürzen.' },
  { id: 'lpic2-209-7', topicId: 10, question: 'Welcher Samba-Daemon ist für das Browsing in der Netzwerkumgebung und die Namensauflösung (WINS/NetBIOS) zuständig?', options: ['smbd', 'nmbd', 'winbindd', 'samba-ad'], answer: 1, explanation: '`nmbd` kümmert sich um die NetBIOS-over-TCP/IP Namensdienste.' },
  { id: 'lpic2-209-8', topicId: 10, question: 'Wie mounten Sie eine NFS-Freigabe (server:/data) in das lokale Verzeichnis /mnt/nfs?', options: ['mount -t nfs server:/data /mnt/nfs', 'mount nfs://server/data /mnt/nfs', 'nfs-mount server:/data /mnt/nfs', 'net use /mnt/nfs server:/data'], answer: 0, explanation: 'Dies ist der Standardbefehl zum Einbinden ferner NFS-Dateisysteme.' },
  { id: 'lpic2-209-9', topicId: 10, question: 'Welcher Befehl zeigt die verfügbaren NFS-Freigaben auf einem entfernten Server an?', options: ['showmount -e <IP>', 'nfs-ls <IP>', 'exportfs -v', 'net view <IP>'], answer: 0, explanation: '`showmount -e` fragt den Mount-Daemon des Servers nach seiner Export-Liste ab.' },
  { id: 'lpic2-209-10', topicId: 10, question: 'Was ist der Zweck des Parameters `writable = yes` in einer Samba-Freigabe?', options: ['Erlaubt Benutzern das Erstellen von Dateien', 'Aktiviert Verschlüsselung', 'Versteckt die Freigabe', 'Begrenzt die Dateigröße'], answer: 0, explanation: 'Ohne diesen Parameter ist die Samba-Freigabe standardmäßig schreibgeschützt (Read-Only).' },
  { id: 'lpic2-209-11', topicId: 10, question: 'Wie heißt das Tool, das die Samba-Konfigurationsdatei auf Syntaxfehler prüft?', options: ['smbcheck', 'testparm', 'samba-conf', 'grep error smb.conf'], answer: 1, explanation: '`testparm` parst die `smb.conf` und zeigt eventuelle Fehler oder Fehlkonfigurationen an.' },
  { id: 'lpic2-209-12', topicId: 10, question: 'Welche NFS-Version führt ein Statefull-Protokoll ein und benötigt nur einen einzigen TCP-Port (2049) durch die Firewall?', options: ['NFSv2', 'NFSv3', 'NFSv4', 'NFSv5'], answer: 2, explanation: 'NFSv4 vereinfacht das Firewall-Handling massiv, da es kein RPC-Portmapping for mehrere Hilfsdienste mehr benötigt.' },
  { id: 'lpic2-209-13', topicId: 10, question: 'Was macht die Option `all_squash` in `/etc/exports`?', options: ['Kompression aktivieren', 'Alle entfernten Benutzer auf einen anonymen Account (nfsnobody/nobody) abbilden', 'Alle Dateien löschen', 'Verschlüsselung erzwingen'], answer: 1, explanation: '`all_squash` dient der Sicherheit, indem es verhindert, dass entfernte UIDs lokale Berechtigungen übernehmen.' },
  { id: 'lpic2-209-14', topicId: 10, question: 'In welcher Samba-Sektion werden Einstellungen definiert, die für den gesamten Server gelten?', options: ['[global]', '[homes]', '[printers]', '[default]'], answer: 0, explanation: 'Die Sektion `[global]` enthält Parameter für Workgroup, Security-Mode und Logging.' },
  { id: 'lpic2-209-15', topicId: 10, question: 'Welcher Befehl zeigt die aktuellen Samba-Verbindungen und gesperrten Dateien an?', options: ['smbstatus', 'smbcontrol', 'net status', 'nmblookup'], answer: 0, explanation: '`smbstatus` ist ein Berichtswerkzeug für den laufenden `smbd`-Server.' },
  { id: 'lpic2-209-16', topicId: 10, question: 'Welcher NFSv4-Dienst ordnet numerische UIDs/GIDs Namen zu (und umgekehrt), um die Kompatibilität zwischen verschiedenen Systemen zu gewährleisten?', options: ['nfsd', 'rpc.idmapd', 'mountd', 'statd'], answer: 1, explanation: '`rpc.idmapd` ist essentiell für NFSv4, da es Namen wie "user@domain" anstelle von rohen Nummern verwendet.' },

  // --- NEUES BATCH 3 (Themen 210-212) ---
  { id: 'lpic2-210-6', topicId: 11, question: 'Welcher Parameter in der ISC DHCP-Serverkonfiguration (`dhcpd.conf`) bestimmt die Standard-Lease-Zeit in Sekunden?', options: ['max-lease-time', 'default-lease-time', 'lease-duration', 'expire-time'], answer: 1, explanation: '`default-lease-time` wird verwendet, wenn der Client keine spezifische Dauer anfordert.' },
  { id: 'lpic2-210-7', topicId: 11, question: 'Welche Datei speichert die aktiven DHCP-Leases auf dem ISC DHCP-Server?', options: ['/etc/dhcp/dhcpd.conf', '/var/lib/dhcp/dhcpd.leases', '/var/log/dhcpd.log', '/var/run/dhcpd.pid'], answer: 1, explanation: 'Der DHCP-Server schreibt Informationen über vergebene Adressen in die Datei `dhcpd.leases`.' },
  { id: 'lpic2-210-8', topicId: 11, question: 'Welche vier Kontroll-Flags werden in einer PAM-Konfigurationsregel verwendet?', options: ['allow, deny, warn, panic', 'auth, account, password, session', 'user, group, other, all', 'login, shell, network, local'], answer: 1, explanation: 'PAM-Module werden in diese vier Gruppen unterteilt.' },
  { id: 'lpic2-210-9', topicId: 11, question: 'Was passiert in einer PAM-Kette, wenn ein Modul mit dem Flag `requisite` fehlschlägt?', options: ['Die Kette wird sofort mit einem Fehler abgebrochen', 'Der Fehler wird ignoriert', 'Das nächste Modul wird trotzdem ausgeführt', 'Der Benutzer wird zur Eingabe eines Root-Passworts aufgefordert'], answer: 0, explanation: '`requisite` führt bei einem Fehlschlag zum sofortigen Abbruch der Prüfung.' },
  { id: 'lpic2-210-10', topicId: 11, question: 'Auf welchem Port hört LDAP standardmäßig für unverschlüsselte Verbindungen?', options: ['389', '636', '3306', '110'], answer: 0, explanation: 'Port 389 ist der Standard für LDAP, während 636 für LDAPS (SSL/TLS) reserviert ist.' },
  { id: 'lpic2-210-11', topicId: 11, question: 'Wie heißt der Hauptserver-Daemon von OpenLDAP?', options: ['ldap_agent', 'named', 'slapd', 'sssd'], answer: 2, explanation: '`slapd` steht für Stand-Alone LDAP Daemon.' },
  { id: 'lpic2-210-12', topicId: 11, question: 'Welcher Befehl wird verwendet, um Abfragen an einen LDAP-Server zu senden?', options: ['ldapquery', 'ldapsearch', 'ldapfind', 'ldaplookup'], answer: 1, explanation: '`ldapsearch` ist das Standard-Kommandozeilenwerkzeug zum Suchen in einem LDAP-Verzeichnis.' },
  { id: 'lpic2-210-13', topicId: 11, question: 'Zweck von SSSD (System Security Services Daemon)?', options: ['Firewall-Management', 'Zentralisierte Authentifizierung und Caching für Remote-Identitätsanbieter wie LDAP oder AD', 'Speichern von Passwörtern in der Cloud', 'Datenbank-Replikation'], answer: 1, explanation: 'SSSD stellt Remote-Identitäten lokal zur Verfügung und ermöglicht Offline-Logins durch Caching.' },
  { id: 'lpic2-210-14', topicId: 11, question: 'Welche OpenVPN-Konfigurationsanweisung leitet den gesamten Client-Internetverkehr durch das VPN?', options: ['redirect-gateway def1', 'route 0.0.0.0 0.0.0.0', 'push "gateway 10.8.0.1"', 'client-to-client'], answer: 0, explanation: '`redirect-gateway def1` überschreibt das Standard-Gateway des Clients.' },
  { id: 'lpic2-210-15', topicId: 11, question: 'Welcher Befehl gibt eine DHCP-Lease explizit frei?', options: ['dhclient -r', 'dhclient -v', 'ifdown eth0', 'ip addr flush eth0'], answer: 0, explanation: 'Der Schalter `-r` (release) sendet eine DHCPRELEASE-Nachricht an den Server.' },
  { id: 'lpic2-210-16', topicId: 11, question: 'Wo werden in einer OpenVPN-Konfiguration die Zertifikate (CA, Server, Client) normalerweise referenziert?', options: ['In der Datei `/etc/hosts`', 'Innerhalb der `.ovpn`-Dateien mittels Pfadangaben oder Inline-Blöcken', 'In der Kernel-Konfiguration', 'In `bashrc`'], answer: 1, explanation: 'OpenVPN-Konfigurationsdateien nutzen Direktiven wie `ca`, `cert` und `key`.' },

  { id: 'lpic2-211-6', topicId: 12, question: 'Welcher Befehl zeigt die aktuelle Postfix-Mail-Warteschlange (Mail Queue) an?', options: ['mailq', 'postqueue -p', 'Beide (A und B)', 'postfix show'], answer: 2, explanation: 'Sowohl `mailq` als auch `postqueue -p` geben eine Liste der ausstehenden Dokumente aus.' },
  { id: 'lpic2-211-7', topicId: 12, question: 'Wie löschen Sie alle Nachrichten in der Postfix-Warteschlange manuell?', options: ['postsuper -d ALL', 'rm -rf /var/spool/postfix/*', 'postfix clear', 'mailq --delete'], answer: 0, explanation: '`postsuper` ist das Superuser-Tool für die Warteschlangenverwaltung.' },
  { id: 'lpic2-211-8', topicId: 12, question: 'Welche Direktive in der `main.cf` bestimmt, für welche Domänen der Postfix-Server autoritativ ist und Mails lokal zustellt?', options: ['myhostname', 'mynetworks', 'mydestination', 'relay_domains'], answer: 2, explanation: 'Mails für Domains in `mydestination` werden nicht weitergeleitet, sondern lokal in Postfächer einsortiert.' },
  { id: 'lpic2-211-9', topicId: 12, question: 'Wie konfigurieren Sie Postfix, um E-Mails von bekannten Spam-IPs mittels DNSBL (Real-time Blackhole List) abzulehnen?', options: ['smtpd_client_restrictions = reject_rbl_client <RBL_DOMAIN>', 'block_ips = <FILE>', 'header_checks = reject', 'spam_filter = on'], answer: 0, explanation: 'Dies ist die Standardmethode, um Echtzeit-Checkups gegen öffentliche Blacklists durchzuführen.' },
  { id: 'lpic2-211-10', topicId: 12, question: 'Standard-Port für POP3?', options: ['25', '110', '143', '993'], answer: 1, explanation: 'Port 110 wird für das Abrufen von Mails via POP3 verwendet.' },
  { id: 'lpic2-211-11', topicId: 12, question: 'Welcher Port wird für IMAPS (IMAP über SSL/TLS) verwendet?', options: ['143', '465', '587', '993'], answer: 3, explanation: 'Port 993 ist für gesichertes IMAP reserviert.' },
  { id: 'lpic2-211-12', topicId: 12, question: 'Zweck von Sieve?', options: ['Mails verschlüsseln', 'Serverseitige E-Mail-Filterung (z.B. in Ordner verschieben oder Weiterleiten), oft integriert in Dovecot', 'DNS-Einträge verwalten', 'Spam-Mails löschen'], answer: 1, explanation: 'Sieve ist eine standardisierte Sprache zur Filterung von E-Mails bei der Zustellung.' },
  { id: 'lpic2-211-13', topicId: 12, question: 'In welcher Datei werden Procmail-Regeln normalerweise benutzerbezogen festgelegt?', options: ['~/.procmailrc', '/etc/procmail.conf', '~/.forward', '/var/mail/.rules'], answer: 0, explanation: 'Procmail sucht standardmäßig im Home-Verzeichnis nach der Konfigurationsdatei `.procmailrc`.' },
  { id: 'lpic2-211-14', topicId: 12, question: 'Was ist der Zweck der Direktive `mynetworks` in Postfix?', options: ['IPs blockieren', 'Definiert die vertrauenswürdigen Netzwerke, die Mails über diesen Server relayen dürfen', 'Nameserver festlegen', 'Virtuelle Domänen konfigurieren'], answer: 1, explanation: 'Clients in `mynetworks` dürfen Mails an beliebige Ziele senden (Open Relay für interne Netze).' },
  { id: 'lpic2-211-15', topicId: 12, question: 'Welcher Befehl erzwingt die sofortige Zustellung aller aufgeschobenen (deferred) Mails?', options: ['postfix flush', 'postqueue -f', 'Beide (A und B)', 'mailq -r'], answer: 2, explanation: 'Sowohl `postfix flush` als auch `postqueue -f` lösen einen "Flush" der Queue aus.' },
  { id: 'lpic2-211-16', topicId: 12, question: 'Zweck von `virtual_alias_maps`?', options: ['Virtuelle Hardware verwalten', 'E-Mails von einer Adresse auf eine oder mehrere andere Adressen (lokal oder extern) umleiten', 'Webserver-Aliase erstellen', 'Passwort-Hashing'], answer: 1, explanation: 'Mapping von Empfängeradressen auf andere Ziele.' },

  { id: 'lpic2-212-6', topicId: 13, question: 'Welche Option bei `iptables` fügt eine Regel am Ende einer Kette hinzu?', options: ['-I', '-A', '-D', '-R'], answer: 1, explanation: '`-A` steht für Append (Anhängen).' },
  { id: 'lpic2-212-7', topicId: 13, question: 'Wie listen Sie alle Regeln der Tabelle `nat` auf?', options: ['iptables -L', 'iptables -t nat -L', 'iptables -nL --nat', 'iptables-save nat'], answer: 1, explanation: '`-t nat` spezifiziert die Ziel-Tabelle.' },
  { id: 'lpic2-212-8', topicId: 13, question: 'Welche IPTables-Kette verarbeitet Pakete, die direkt an den lokalen Server adressiert sind?', options: ['FORWARD', 'OUTPUT', 'INPUT', 'PREROUTING'], answer: 2, explanation: 'Die `INPUT`-Kette filtert den eingehenden Verkehr an lokale Sockets.' },
  { id: 'lpic2-212-9', topicId: 13, question: 'Zweck des Targets `MASQUERADE`?', options: ['Pakete verschlüsseln', 'Dynamisches Source-NAT (SNAT); ersetzt die Quell-IP durch die IP der ausgehenden Schnittstelle', 'Traffic drosseln', 'Ports scannen'], answer: 1, explanation: 'Besonders nützlich bei Internetverbindungen mit dynamischen IPs.' },
  { id: 'lpic2-212-10', topicId: 13, question: 'Welcher Nmap-Scan-Typ führt einen "Stealth" (halboffenen) TCP-Scan durch?', options: ['-sT', '-sU', '-sS', '-sA'], answer: 2, explanation: 'Der SYN-Scan (`-sS`) schließt den TCP-Handshake nicht ab und ist daher schwerer zu loggen.' },
  { id: 'lpic2-212-11', topicId: 13, question: 'Wie erkennt Nmap das Betriebssystem eines Zielhosts?', options: ['-O', '-sV', '-A', 'Beide (A und C)'], answer: 3, explanation: '`-O` ist der spezifische Schalter; `-A` ist der "Aggressive"-Modus, der ihn beinhaltet.' },
  { id: 'lpic2-212-12', topicId: 13, question: 'In welcher Datei konfigurieren Sie in Fail2ban die spezifischen Sperrregeln (Jails)?', options: ['jail.conf', 'jail.local', 'filters.d/', 'fail2ban.conf'], answer: 1, explanation: '`jail.local` sollte für eigene Konfigurationen verwendet werden, um Überschreiben bei Updates zu vermeiden.' },
  { id: 'lpic2-212-13', topicId: 13, question: 'Zweck von `bantime` in Fail2ban?', options: ['Zeitraum der Log-Analyse', 'Dauer der IP-Sperrung in Sekunden', 'Maximaler Zeitraum zwischen Fehlversuchen', 'Zeit bis zum Neustart'], answer: 1, explanation: 'Legt fest, wie lange eine erkannte IP geblockt wird.' },
  { id: 'lpic2-212-14', topicId: 13, question: 'Was ist Netfilter?', options: ['Ein grafisches Firewall-Frontend', 'Das Framework im Linux-Kernel, das Paketfilterung und NAT ermöglicht (Basis von IPTables)', 'Ein VPN-Protokoll', 'Ein Proxy-Server'], answer: 1, explanation: 'Netfilter stellt die Hooks im Kernel bereit.' },
  { id: 'lpic2-212-15', topicId: 13, question: 'Welcher Befehl wird verwendet, um IPTables-Regeln so zu speichern, dass sie beim nächsten Booten geladen werden können (je nach Distro-Scripts)?', options: ['iptables-save', 'iptables-restore', 'service iptables save', 'Beide (A und C)'], answer: 3, explanation: '`iptables-save` exporter die Regeln; viele Distributionen bieten Wrapper-Dienste.' },
  { id: 'lpic2-212-16', topicId: 13, question: 'Was ist in OpenVAS ein NVT?', options: ['Network virtual terminal', 'Network Vulnerability Test; ein Skript zur Erkennung einer spezifischen Schwachstelle', 'Neuer VPN-Tunnel', 'Next vulnerability tool'], answer: 1, explanation: 'NVTs sind die Testmodule von OpenVAS.' },
  { id: 'lpic2-212-17', topicId: 13, question: 'Welcher IPTables-Befehl löscht (flushed) alle Regeln aus allen Ketten der aktuellen Tabelle?', options: ['iptables -X', 'iptables -Z', 'iptables -F', 'iptables -R'], answer: 2, explanation: '`-F` löscht alle Regeln in der gewählten Tabelle.' },
];
